まず、エージェントA がオブジェクトを作成する: # エージェントA: 地面を作成 curl -X POST http://localhost:8769/call_tool \ -H "Content-Type: application/json" \ -d '{ "tool_name": "create_gameobject", "parameters": { "name": "Ground", "type": "Plane", "position": {"x": 0, "y": 0, "z": 0}, "scale": {"x": 10, "y": 1, "z": 10} } }' 同時に、エージェントB がスクリプトを作成する: # エージェントB: プレイヤー制御スクリプトを作成 curl -X POST http://localhost:8769/call_tool \ -H "Content-Type: application/json" \ -d '{ "tool_name": "create_script", "parameters": { "name": "PlayerController", "code": "using UnityEngine;

public class PlayerController : MonoBehaviour
{
 public float speed = 5f;

 void Update()
 {
 float h = Input.GetAxis("Horizontal");
 float v = Input.GetAxis("Vertical");
 transform.Translate(new Vector3(h, 0, v) * speed * Time.deltaTime);
 }
}" } }' エージェントA がプレイヤーオブジェクトを作成してスクリプトを適用する: # エージェントA: プレイヤーを作成 curl -X POST http://localhost:8769/call_tool \ -H "Content-Type: application/json" \ -d '{ "tool_name": "create_gameobject", "parameters": { "name": "Player", "type": "Capsule", "position": {"x": 0, "y": 1, "z": 0} } }' # エージェントA: スクリプトを適用 curl -X POST http://localhost:8769/call_tool \ -H "Content-Type: application/json" \ -d '{ "tool_name": "add_component", "parameters": { "object_name": "Player", "component_type": "PlayerController" } }'

curl を1つずつ実行するのは面倒なので、Python スクリプトで自動化してみよう。 import requests import concurrent.futures import json API_BASE = "http://localhost:8769" def call_tool(tool_name: str, parameters: dict) -> dict: """OpenForge MCP のツールを呼び出す""" response = requests.post( f"{API_BASE}/call_tool", json={"tool_name": tool_name, "parameters": parameters}, ) response.raise_for_status() return response.json() def list_tools(category: str = "") -> dict: """利用可能なツール一覧を取得する""" response = requests.post( f"{API_BASE}/list_tools", json={"category": category}, ) response.raise_for_status() return response.json() def agent_scene_builder(): """エージェントA: シーン構築を担当""" print("[A] 地面を作成中...") call_tool("create_gameobject", { "name": "Ground", "type": "Plane", "position": {"x": 0, "y": 0, "z": 0}, "scale": {"x": 10, "y": 1, "z": 10}, }) print("[A] 壁を作成中...") walls = [ {"name": "Wall_North", "pos": {"x": 0, "y": 1, "z": 50}}, {"name": "Wall_South", "pos": {"x": 0, "y": 1, "z": -50}}, {"name": "Wall_East", "pos": {"x": 50, "y": 1, "z": 0}}, {"name": "Wall_West", "pos": {"x": -50, "y": 1, "z": 0}}, ] for wall in walls: call_tool("create_gameobject", { "name": wall["name"], "type": "Cube", "position": wall["pos"], "scale": {"x": 100, "y": 2, "z": 1}, }) print("[A] シーン構築完了") def agent_script_writer(): """エージェントB: スクリプト作成を担当""" print("[B] PlayerController スクリプトを作成中...") call_tool("create_script", { "name": "PlayerController", "code": ( "using UnityEngine;

" "public class PlayerController : MonoBehaviour
" "{
" " public float speed = 5f;

" " void Update()
" " {
" ' float h = Input.GetAxis("Horizontal");
' ' float v = Input.GetAxis("Vertical");
' " transform.Translate(new Vector3(h, 0, v) * speed * Time.deltaTime);
" " }
" "}" ), }) print("[B] ItemCollector スクリプトを作成中...") call_tool("create_script", { "name": "ItemCollector", "code": ( "using UnityEngine;

" "public class ItemCollector : MonoBehaviour
" "{
" " public int score = 0;

" " void OnTriggerEnter(Collider other)
" " {
" ' if (other.CompareTag("Collectible"))
' " {
" " score++;
" " Destroy(other.gameObject);
" " }
" " }
" "}" ), }) print("[B] スクリプト作成完了") def main(): # 2つのエージェントを並列実行 with concurrent.futures.ThreadPoolExecutor(max_workers=2) as executor: future_a = executor.submit(agent_scene_builder) future_b = executor.submit(agent_script_writer) # 両方の完了を待つ concurrent.futures.wait([future_a, future_b]) # 両方完了後、スクリプトをオブジェクトに適用 print("[統合] プレイヤーを作成してスクリプトを適用中...") call_tool("create_gameobject", { "name": "Player", "type": "Capsule", "position": {"x": 0, "y": 1, "z": 0}, }) call_tool("add_component", { "object_name": "Player", "component_type": "Rigidbody", }) call_tool("add_component", { "object_name": "Player", "component_type": "PlayerController", }) call_tool("add_component", { "object_name": "Player", "component_type": "ItemCollector", }) print("すべての作業が完了しました") if __name__ == "__main__": main() このスクリプトを実行すると、シーン構築とスクリプト作成が並行して進む。両方が完了した後で、オブジェクトとスクリプトを統合するよ。 依存関係の管理 並列実行するタスクは、お互いに依存しないようにするのが鍵。上の例では「シーン構築」と「スクリプト作成」は独立した作業なので並列にできる。「スクリプトの適用」はどちらにも依存するので、両方が完了してから実行しているよ。

curl -X POST http://localhost:8769/call_tool \ -H "Content-Type: application/json" \ -d '{ "tool_name": "create_script", "parameters": { "name": "PlayerController", "path": "Assets/Scripts/PlayerController.cs", "content": "using UnityEngine;

public class PlayerController : MonoBehaviour
{
 public float speed = 5f;
 void Update()
 {
 float h = Input.GetAxis("Horizontal");
 float v = Input.GetAxis("Vertical");
 transform.Translate(new Vector3(h, 0, v) * speed * Time.deltaTime);
 }
}" } }'
